/**
 * @param {Config} config
 * @param {Context} context
 * Do not edit this comment or parameter types. Required for code suggestions
*/
exports.main = function (config, context) {


	config.addScriptLine("configure");
	config.addScriptLine("snmp-server contact snmpcontact");
	config.addScriptLine("exit");

	function warn(msg) {
		//config.addScriptLine("# - " + msg);
		config.warnLog(msg);
	}


	var helper = config.getScalarByOid("2.1.4");

	warn("helper: " + helper);


	if (helper != "snmpcontact") {
		createSNMPaccess();
	}
	function createSNMPaccess() {
		config.addScriptLine("configure");
		config.addScriptLine("snmp-server view \"any\" iso included");
		//config.addScriptLine("snmp-server group " + context.vars.SNMP_Group +" v3 priv notify \"Default\" read \"any\" write \"any\"");
        config.addScriptLine("snmp-server group \" " + context.vars.SNMP_Group + "\" v3 priv notify \"Default\" read \"any\" write \"any\"");
		config.addScriptLine("snmp-server user \" " +context.vars.SNMP_USER + "\" \" " + context.vars.SNMP_Group + "\" auth-sha " + context.vars.SNMP_AUTH_PW  + " priv-aes " + context.vars.SNMP_PRIV_PW + "");
		config.addScriptLine("exit");


	}
}
